Definir Funcao ValidarCaminhoMarcacao();
Definir Funcao ValidarExtensaoMarcacao();
Definir Funcao ValidarCaminhoRede();

Definir Alfa diretorioMarcacao;
Definir Numero caminhoMarcacaoValido;
Definir Numero extensaoMarcacaoValido;
Definir Numero prefixoCaminhoMarcacaoValido;

Definir Cursor Cur_R058MOD;
Definir Numero vCaracter;
Definir Numero dirmarExtensaoValido;
Definir Numero dirrejExtensaoValido;
Definir Numero dirmarValido;
Definir Numero dirrejValido;
Definir Numero achouDirmar;
Definir Numero achouDirrej;
Definir Numero dirmarCaminhoRedeValido;
Definir Numero dirrejCaminhoRedeValido;

Cur_R058MOD.SQL "SELECT DIRMAR, DIRREJ \
                 FROM R058MOD \
                 WHERE modcol = 96";

Cur_R058MOD.AbrirCursor();
Se (Cur_R058MOD.Achou)
    Inicio
    vCaracter = 0;

    @ Valida se dirmar existe @    
    Se (Cur_R058MOD.DIRMAR = "NULL")
      achouDirmar = 0;
    Senao
      Inicio
        LerPosicaoAlfa (Cur_R058MOD.DIRMAR, vCaracter, 1);
        Se (vCaracter = ' ')
          achouDirmar = 0;
        Senao
          achouDirmar = 1;
      Fim;

    @ Valida se dirrej existe @    
    Se (Cur_R058MOD.DIRREJ = "NULL")
      achouDirrej = 0;
    Senao
      Inicio
        LerPosicaoAlfa (Cur_R058MOD.DIRREJ, vCaracter, 1);
        Se (vCaracter = ' ')
          achouDirrej = 0;
        Senao
          achouDirrej = 1;
      Fim;

    @ Valida se deretorios sao validos @
    Se (achouDirmar = 1)
      Inicio
      diretorioMarcacao = Cur_R058MOD.DIRMAR;
      ValidarExtensaoMarcacao();
      dirmarExtensaoValido = extensaoMarcacaoValido;
      ValidarCaminhoMarcacao();
      dirmarValido = caminhoMarcacaoValido;
      ValidarCaminhoRede();
      dirmarCaminhoRedeValido = prefixoCaminhoMarcacaoValido;
      Fim;

    Se (achouDirrej = 1)
      Inicio
      diretorioMarcacao = Cur_R058MOD.DIRREJ;
      ValidarExtensaoMarcacao();
      dirrejExtensaoValido = extensaoMarcacaoValido;
      ValidarCaminhoMarcacao();
      dirrejValido = caminhoMarcacaoValido;
      ValidarCaminhoRede();
      dirrejCaminhoRedeValido = prefixoCaminhoMarcacaoValido;
      Fim;

    @ Exibe resultado @
    Se (achouDirmar = 0)
      Inicio
      valorMemo = "Diretório para arquivos de marcações não informado no coletor Mobilidade.";
      icone = "erro";
      ListaSecao("AdicionalPadrao");
      Fim;
    Senao
      Inicio
        Se (dirmarExtensaoValido = 0)
          Inicio
          valorMemo = "Diretório para arquivos de marcações informado no coletor Mobilidade deve terminar com o caminho \"\\*.txt\". Exemplo: \"\\\\computador01\\*.txt\".";
          icone = "erro";
          ListaSecao("AdicionalPadrao");
          Fim; 

        Se (dirmarCaminhoRedeValido = 0)
          Inicio
          valorMemo = "Diretório para arquivos de marcações informado no coletor Mobilidade deve ser um caminho de rede. Exemplo: \"\\\\computador01\\*.txt\".";
          icone = "erro";
          ListaSecao("AdicionalPadrao");
          Fim; 

        Se (dirmarValido = 0)
          Inicio
          valorMemo = "Diretório para arquivos de marcações informado no coletor Mobilidade não existe.";
          icone = "erro";
          ListaSecao("AdicionalPadrao");
          Fim;
      Fim;

    Se (achouDirrej = 0)
      Inicio
      valorMemo = "Diretório para marcações rejeitadas não informado no coletor Mobilidade.";
      icone = "erro";
      ListaSecao("AdicionalPadrao");
      Fim;
    Senao
      Inicio
        Se (dirrejExtensaoValido = 0)      
          Inicio
          valorMemo = "Diretório para marcações rejeitadas informado no coletor Mobilidade deve terminar com o caminho \"\\*.txt\". Exemplo: \"\\\\computador01\\*.txt\".";
          icone = "erro";
          ListaSecao("AdicionalPadrao");
          Fim;

        Se (dirrejCaminhoRedeValido = 0)
          Inicio
          valorMemo = "Diretório para marcações rejeitadas informado no coletor Mobilidade deve ser um caminho de rede. Exemplo: \"\\\\computador01\\*.txt\".";
          icone = "erro";
          ListaSecao("AdicionalPadrao");
          Fim;

        Se (dirrejValido = 0)
          Inicio
          valorMemo = "Diretório para marcações rejeitadas informado no coletor Mobilidade não existe.";
          icone = "erro";
          ListaSecao("AdicionalPadrao");
          Fim;  
      Fim;

    Se ((achouDirmar = 1) e (achouDirrej = 1) e (dirmarValido = 1) e (dirrejValido = 1) e (dirmarExtensaoValido = 1) e (dirrejExtensaoValido = 1) e (dirmarCaminhoRedeValido = 1) e (dirrejCaminhoRedeValido = 1))
      Inicio
      valorMemo = "Coletor cadastrado corretamente.";
      icone = "ok";
      ListaSecao("AdicionalPadrao");
      Fim;

    Fim;
Senao
    Inicio
    valorMemo = "Não encontrado coletor do tipo Mobilidade.";
    icone = "erro";
    ListaSecao("AdicionalPadrao");
    Fim;

Cur_R058MOD.FecharCursor(); 

Funcao ValidarCaminhoMarcacao();
  Inicio
  Definir Numero tamanhoDirMarc;
  Definir Alfa caminhoDirMarc;

  TamanhoAlfa(diretorioMarcacao, tamanhoDirMarc);
  caminhoDirMarc = diretorioMarcacao;
  CopiarAlfa(caminhoDirMarc, 0, tamanhoDirMarc - 5);

  caminhoMarcacaoValido = ExisteDiretorio(caminhoDirMarc);
  Fim;

Funcao ValidarExtensaoMarcacao();
  Inicio
  Definir Numero tamanhoDirMarc;
  Definir Alfa extensaoDirMarc;

  TamanhoAlfa(diretorioMarcacao, tamanhoDirMarc);
  extensaoDirMarc = diretorioMarcacao; 
  CopiarAlfa(extensaoDirMarc, tamanhoDirMarc - 5, 6);

  Se (extensaoDirMarc = "\\*.txt")
    extensaoMarcacaoValido = 1;
  Senao
    extensaoMarcacaoValido = 0;

  Fim;

Funcao ValidarCaminhoRede();
  Inicio
  Definir Numero tamanhoDirMarc;
  Definir Alfa prefixoRede;

  TamanhoAlfa(diretorioMarcacao, tamanhoDirMarc);
  prefixoRede = diretorioMarcacao; 
  CopiarAlfa(prefixoRede, 0, 2);

  Se (prefixoRede = "\\\\")
    prefixoCaminhoMarcacaoValido = 1;
  Senao
    prefixoCaminhoMarcacaoValido = 0;  
  Fim;

