Funcao VerificarEmailAdministrador();
  Inicio
  Cur_R900CPL.SQL "SELECT email \
                    FROM R900cpl \
                    WHERE email = :emailUsuario \
                    AND perid in ( \
                    	SELECT codmbr \
                    	FROM R910MGP \
                     	WHERE codgrp in ( \
                    		SELECT codent \
                    		FROM r910ent \
                    		WHERE nomexb in ( \
