Funcao VerificarEmails();
  Inicio
  Cur_R900CPL.SQL "SELECT email \
                    FROM R900cpl \
                    WHERE perid in ( \
                    	SELECT codmbr \
                    	FROM R910MGP \
                    	WHERE codgrp in ( \
                    		SELECT codent \
                    		FROM r910ent \
                    		WHERE nomexb in ( \
                    			:nomeGrupo \
                    		) \
                    	) \
                    ) \
                  AND EMAIL IS NOT NULL \
                  GROUP BY email \
                  HAVING COUNT(*) > 1";

  Cur_R900CPL.AbrirCursor();
  Se (Cur_R900CPL.Achou)
    Inicio
    emailsOk = 0;

    Enquanto (Cur_R900CPL.Achou)
      Inicio
      emailDuplicado = Cur_R900CPL.EMAIL;
