                    FROM R900cpl \
                    WHERE perid in ( \
                    	SELECT codmbr \
                    	FROM R910MGP \
                    	WHERE codgrp in ( \
                    		SELECT codent \
                    		FROM r910ent \
                    		WHERE nomexb in ( \
                    			:nomeGrupo \
                    		) \
                    	) \
                    ) \
                  AND EMAIL IS NULL \
                  GROUP BY email";

  Cur2_R900CPL.AbrirCursor();
  Se (Cur2_R900CPL.Achou)
    Inicio
    emailsOk = 0;

    Enquanto (Cur2_R900CPL.Achou)
